import React, { useState } from "react";
import { Trash2, Pencil, Plus } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { linkHomeDesign as design } from "../../design/linkHomeDesign";

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!name.trim()) return;

    if (editingId) {
      setLinks(
        links.map((link) =>
          link.id === editingId ? { ...link, name } : link
        )
      );
      setEditingId(null);
    } else {
      setLinks([...links, { id: Date.now(), name }]);
    }

    setName("");
  };

  const handleEdit = (link) => {
    setName(link.name);
    setEditingId(link.id);
  };

  const handleDelete = (id) => {
    setLinks(links.filter((link) => link.id !== id));
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* HEADER */}
        <div className={design.headerWrapper}>
          <div>
            <h1 className={design.title}>Navigation Links</h1>
            <p className={design.subtitle}>
              Manage main navigation links shown on the public website.
            </p>
          </div>
        </div>

        {/* FORM CARD */}
        <div className={design.card}>
          <div className={design.formSection}>
            <form
              onSubmit={handleSubmit}
              className="flex flex-col sm:flex-row gap-4"
            >
              <input
                type="text"
                placeholder="Enter link name"
                value={name}
                onChange={(e) => setName(e.target.value)}
                className={design.input}
              />

              <motion.button
                whileTap={{ scale: 0.96 }}
                type="submit"
                className={design.buttonPrimary}
              >
                <Plus size={16} />
                {editingId ? "Update Link" : "Add Link"}
              </motion.button>
            </form>
          </div>

          {/* TABLE SECTION */}
          <div className={design.tableWrapper}>
            {/* Desktop Header */}
            <div className={design.tableHeader}>
              <div>Name</div>
              <div className="text-right">Actions</div>
            </div>

            <AnimatePresence>
              {links.length === 0 ? (
                <div className={design.emptyState}>
                  No links created yet.
                </div>
              ) : (
                links.map((link) => (
                  <motion.div
                    key={link.id}
                    initial={{ opacity: 0, y: 8 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.2 }}
                    className={design.tableRow}
                  >
                    {/* LEFT */}
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-4">
                        <span className="font-medium text-slate-800">
                          {link.name}
                        </span>
                        <span className={design.badge}>
                          Active
                        </span>
                      </div>

                      {/* Mobile Actions */}
                      <div className="flex gap-4 md:hidden">
                        <button
                          onClick={() => handleEdit(link)}
                          className="text-slate-500 hover:text-indigo-600 transition"
                        >
                          <Pencil size={18} />
                        </button>
                        <button
                          onClick={() => handleDelete(link.id)}
                          className="text-slate-500 hover:text-red-600 transition"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    </div>

                    {/* Desktop Actions */}
                    <div className="hidden md:flex justify-end gap-5">
                      <button
                        onClick={() => handleEdit(link)}
                        className="text-slate-500 hover:text-indigo-600 transition"
                      >
                        <Pencil size={18} />
                      </button>

                      <button
                        onClick={() => handleDelete(link.id)}
                        className="text-slate-500 hover:text-red-600 transition"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </motion.div>
                ))
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
